/**
 * Types pour le module d'analyse AEO.
 * Alignés avec le schéma DB et les services d'analyse.
 */

/** Niveaux de priorité des recommandations */
export type Priority = 'critical' | 'high' | 'medium' | 'low'

/** Niveaux d'effort/impact */
export type EffortLevel = 'low' | 'medium' | 'high'

/** Grades AEO */
export type AeoGrade = 'A+' | 'A' | 'B' | 'C' | 'D' | 'F'

/** Statut d'un critère dans l'analyse */
export type CriterionStatus = 'success' | 'warning' | 'error'

/** Recommandation d'amélioration AEO */
export interface Recommendation {
  id: string
  priority: Priority
  title: string
  description: string
  action: string
  effort: EffortLevel
  impact: EffortLevel
  category: string
}

/** Score d'une catégorie de l'analyse */
export interface CategoryScore {
  name: string
  score: number
  weight: number
  items: CriterionResult[]
}

/** Résultat d'un critère individuel */
export interface CriterionResult {
  status: CriterionStatus
  message: string
}

/** Noeud du graphe de connaissances */
export interface GraphNode {
  id: string
  label: string
  type: 'entity' | 'keyword' | 'competitor' | 'source'
  val: number
}

/** Lien du graphe de connaissances */
export interface GraphLink {
  source: string
  target: string
  strength: number
}

/** Données de citation IA */
export interface AiCitationData {
  before: string
  after: string
  probability: number
}

/** Solution générée par l'IA */
export interface GeneratedSolution {
  title: string
  explanation: string
  content: string
  type: 'code' | 'text'
  language?: 'html' | 'json' | 'text' | 'markdown'
  implementationSteps: string[]
}

/** Résultat complet d'une analyse (format applicatif) */
export interface AnalysisResult {
  id: string
  url: string
  timestamp: string
  globalScore: number
  grade: AeoGrade
  categories: Record<string, CategoryScore>
  recommendations: Recommendation[]
  aiCitation: AiCitationData
  knowledgeGraph: {
    nodes: GraphNode[]
    links: GraphLink[]
  }
  generatedSolutions?: Record<string, GeneratedSolution & { timestamp: string }>
}

/** Contenu généré dans le Studio AEO */
export interface SMCContent {
  id: string
  type: 'fiche' | 'faq' | 'brief' | 'article'
  title: string
  content: string
  timestamp: string
}

/** Données de comparaison benchmark */
