/**
 * Utilitaires généraux pour CitedBy.ai.
 */

/** Formater une date en français */
export function formatDateFR(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('fr-FR', {
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  })
}

/** Formater une date relative (il y a X minutes/heures/jours) */
export function formatRelativeDate(dateStr: string): string {
  const now = new Date()
  const date = new Date(dateStr)
  const diffMs = now.getTime() - date.getTime()
  const diffMinutes = Math.floor(diffMs / 60000)
  const diffHours = Math.floor(diffMs / 3600000)
  const diffDays = Math.floor(diffMs / 86400000)

  if (diffMinutes < 1) return "À l'instant"
  if (diffMinutes < 60) return `Il y a ${diffMinutes} min`
  if (diffHours < 24) return `Il y a ${diffHours}h`
  if (diffDays < 7) return `Il y a ${diffDays}j`
  return formatDateFR(dateStr)
}

/** Formater un prix en euros (centimes → euros) */
export function formatPrice(cents: number): string {
  return new Intl.NumberFormat('fr-FR', {
    style: 'currency',
    currency: 'EUR',
  }).format(cents / 100)
}

/** Formater un nombre avec séparateur de milliers */
export function formatNumber(n: number): string {
  return new Intl.NumberFormat('fr-FR').format(n)
}

/** Extraire le domaine d'une URL */
export function extractDomain(url: string): string {
  try {
    const parsed = new URL(url.startsWith('http') ? url : `https://${url}`)
    return parsed.hostname.replace('www.', '')
  } catch {
    return url
  }
}

/** Valider une URL */
export function isValidUrl(url: string): boolean {
  try {
    const parsed = new URL(url.startsWith('http') ? url : `https://${url}`)
    return parsed.protocol === 'https:' || parsed.protocol === 'http:'
  } catch {
    return false
  }
}

/** Obtenir le grade AEO à partir du score */
export function getGradeFromScore(score: number): 'A+' | 'A' | 'B' | 'C' | 'D' | 'F' {
  if (score >= 90) return 'A+'
  if (score >= 80) return 'A'
  if (score >= 65) return 'B'
  if (score >= 50) return 'C'
  if (score >= 30) return 'D'
  return 'F'
}

/** Obtenir la couleur Tailwind associée au grade */
export function getGradeColor(grade: string): string {
  switch (grade) {
    case 'A+': case 'A': return 'text-score-excellent'
    case 'B': return 'text-score-good'
    case 'C': return 'text-score-average'
    case 'D': case 'F': return 'text-score-poor'
    default: return 'text-slate-400'
  }
}

/** Obtenir la couleur de fond associée au score */
export function getScoreColor(score: number): string {
  if (score >= 80) return '#10B981'
  if (score >= 65) return '#3B82F6'
  if (score >= 50) return '#F59E0B'
  return '#EF4444'
}

/** Tronquer un texte */
export function truncate(text: string, maxLength: number): string {
  if (text.length <= maxLength) return text
  return text.slice(0, maxLength - 3) + '...'
}

/** Générer un ID unique simple */
export function generateId(): string {
  return crypto.randomUUID()
}
